function renderStagingUI() {
    const list = document.getElementById('staging-list');
    if (!list) return;
    list.innerHTML = '';

    pendingOps.forEach((op, i) => {
        if (op.action === 'comment') return;

        const added = op.replace_with || op.content || "";
        const removed = op.find_block || "";
        const typeLabel = op.action === 'replace_block' ? 'MOD' : (op.action === 'create_file' ? 'ADD' : 'DEL');

        const div = document.createElement('div');
        div.className = 'stage-item';
        div.innerHTML = `
            <div class="stage-header" onclick="toggleStageOp(${i}, this)" style="align-items: flex-start;">
                <div style="display:flex; flex-direction:column; gap:4px; align-items:center; width:35px; flex-shrink:0;">
                    <span style="color:var(--ai-accent); font-weight:bold; font-size:10px;">${typeLabel}</span>
                    ${renderDiffMeter(added, removed)}
                </div>
                <span class="stage-path">${op.file_path}</span>
                <button class="menu-btn" style="color:var(--danger); flex-shrink:0; padding: 0 8px; font-size: 18px;" onclick="event.stopPropagation(); removeStagedOp(${i})">×</button>
            </div>
            <div id="stage-body-${i}" style="display:none; padding:12px; background:#0a0a0a; border-top:1px solid var(--border);">
                ${removed ? `<div class="code-block-wrapper"><label class="code-label">Removing</label><pre class="code-pre diff-remove">${escapeHtml(removed)}</pre></div>` : ''}
                ${added ? `<div class="code-block-wrapper"><label class="code-label">Adding</label><pre class="code-pre diff-add">${escapeHtml(added)}</pre></div>` : ''}
                <button class="btn-outline" style="width:100%; margin-top:10px; font-size:11px; padding:8px;" onclick="previewStageDiff(${i})">🔍 Full Side-by-Side Diff</button>
            </div>
        `;
        list.appendChild(div);
    });
}

function toggleStageOp(index, headerEl) {
    const body = document.getElementById(`stage-body-${index}`);
    const isVisible = body.style.display === 'block';

    // Close others
    document.querySelectorAll('[id^="stage-body-"]').forEach(el => el.style.display = 'none');
    document.querySelectorAll('.stage-header').forEach(el => el.style.background = '');

    if (!isVisible) {
        body.style.display = 'block';
        headerEl.style.background = 'rgba(255,255,255,0.03)';
        body.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
}

